mapper.select:
/* com.erns.coching.popup.mapper.PopupDAO.getList */
SELECT ZZ.* FROM ( SELECT
, A1.MEMB_SEQ AS MEMB_SEQ , A1.MEMB_ID AS MEMB_ID , A1.MEMB_NAME AS MEMB_NAME FROM T_POPUP_INF AA LEFT OUTER JOIN T_MEMB_INF A1 ON AA.CHNR = A1.MEMB_SEQ
ORDER BY AA.SORT_ORD, AA.POPUP_SEQ DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.popup.mapper.PopupDAO.load */
SELECT
, BM.POPUP_TYPE , BM.POPUP_MST_NAME FROM T_POPUP_INF AA JOIN T_POPUP_MST BM ON AA.POPUP_MST_CD = BM.POPUP_MST_CD
AND AA.POPUP_SEQ = #{popupSeq , jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.popup.mapper.PopupDAO.insert */


	SELECT nextval('seq_t_popup_inf')


INSERT INTO T_POPUP_INF (
	POPUP_SEQ
	, POPUP_MST_CD
	, POPUP_NAME
	, FROM_DATE
	, TO_DATE
	, POPUP_DESC
	, CLOSE_OPT
	, POPUP_URL
	, POPUP_WIDTH
	, POPUP_HEIGHT
	, CLICKS
	, USE_YN
	, DEL_YN

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
	) VALUES (
		#{popupSeq			, jdbcType=INTEGER}
	, #{popupMstCd 			, jdbcType=VARCHAR}
	, #{popupName			, jdbcType=VARCHAR}
	, #{fromDate			, jdbcType=VARCHAR}
	, #{toDate				, jdbcType=VARCHAR}
	, #{popupDesc			, jdbcType=VARCHAR}
	, COALESCE(#{closeOpt	, jdbcType=CHAR}, '1')
	, #{popupUrl			, jdbcType=VARCHAR}
	, #{popupWidth			, jdbcType=INTEGER}
	, #{popupHeight			, jdbcType=INTEGER}
	, #{clicks				, jdbcType=INTEGER}
	, COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')
	, COALESCE(#{delYn		, jdbcType=CHAR}, 'N')

	, #{rgtr	, jdbcType=INTEGER}
	, now()
	, #{chnr	, jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.coching.popup.mapper.PopupDAO.update */

UPDATE T_POPUP_INF SET
		POPUP_MST_CD     	= #{popupMstCd 			, jdbcType=VARCHAR}
	, POPUP_NAME       	= #{popupName			, jdbcType=VARCHAR}
	, FROM_DATE        	= #{fromDate			, jdbcType=VARCHAR}
	, TO_DATE          	= #{toDate				, jdbcType=VARCHAR}
	, POPUP_DESC       	= #{popupDesc			, jdbcType=VARCHAR}
	, CLOSE_OPT			= COALESCE(#{closeOpt	, jdbcType=CHAR}, '1')
	, POPUP_URL        	= #{popupUrl			, jdbcType=VARCHAR}
	, POPUP_WIDTH      	= #{popupWidth			, jdbcType=INTEGER}
	, POPUP_HEIGHT     	= #{popupHeight			, jdbcType=INTEGER}
	, CLICKS            = #{clicks				, jdbcType=INTEGER}
	, USE_YN            = COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')
	, DEL_YN            = COALESCE(#{delYn		, jdbcType=CHAR}, 'N')

	, CHNR 		 		= #{chnr				, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND POPUP_SEQ 		= #{popupSeq			, jdbcType=INTEGER}

/* com.erns.coching.popup.mapper.PopupDAO.updateUseYn */

UPDATE T_POPUP_INF SET
		USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 		= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND POPUP_MST_CD 	= #{popupMstCd	, jdbcType=VARCHAR}
	AND POPUP_SEQ 		= #{popupSeq	, jdbcType=INTEGER}

/* com.erns.coching.popup.mapper.PopupDAO.updateDelYn */

UPDATE T_POPUP_INF SET
		DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 		= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND POPUP_MST_CD 	= #{popupMstCd	, jdbcType=VARCHAR}
	AND POPUP_SEQ 		= #{popupSeq	, jdbcType=INTEGER}

/* com.erns.coching.popup.mapper.PopupDAO.updateOrder */

UPDATE T_POPUP_INF SET
		SORT_ORD      = #{sortOrd	, jdbcType=INTEGER}

	, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM  	= now()

	AND POPUP_SEQ 	= #{popupSeq, jdbcType=INTEGER}

/* com.erns.coching.popup.mapper.PopupDAO.updateState */

UPDATE T_POPUP_INF SET
		USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')
	,	DEL_YN            = COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

	, CHNR 		 		= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND POPUP_SEQ 	= #{popupSeq, jdbcType=INTEGER}
	AND POPUP_MST_CD 	= #{popupMstCd	, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.popup.mapper.PopupDAO.delete */

DELETE FROM T_POPUP_INF

	AND POPUP_SEQ = #{popupSeq, jdbcType=INTEGER}
